window.ADRIVE_THEME_DATA=window.ADRIVE_THEME_DATA||{};window.ADRIVE_THEME_DATA[16]=[{"id":701000101,"themeId":16,"group":7010001,"chapter":59,"chapters":[59],"q":"Какие из перечисленных признаков являются характерными для артериального кровотечения?","a":["Из раневой поверхности выступают мелкие, точечные капельки крови.","Кровь ярко-красного или алого цвета, выбрасывается сильной пульсирующей струёй.","Кровь тёмно-вишнёвого цвета, вытекает медленно, равномерной и непрерывной струёй."],"c":1,"e":"<p>Артериальное кровотечение легко распознаётся по пульсирующей струе ярко-красной крови, которая вытекает очень быстро.</p>","image":"assets/adrive-questions/q701000101.jpg"},{"id":701000102,"themeId":16,"group":7010001,"chapter":59,"chapters":[59],"q":"Какие из перечисленных признаков являются характерными для венозного кровотечения?","a":["Из раневой поверхности выступают мелкие, точечные капельки крови.","Кровь ярко-красного цвета, выбрасывается сильной пульсирующей струёй.","Кровь тёмно-вишнёвого цвета, вытекает медленно, равномерной непрерывной струёй."],"c":2,"e":"<p>Венозное кровотечение характеризуется тем, что из раны струится тёмная по цвету венозная кровь, которая вытекает равномерно, без пульсации.</p>","image":"assets/adrive-questions/q701000102.jpg"},{"id":701000103,"themeId":16,"group":7010001,"chapter":59,"chapters":[59],"q":"Что из перечисленного ниже является характерным признаком капиллярного кровотечения?","a":["Кровь, которая скапливается по всей поверхности раны, а затем стекает с неё.","Кровь ярко-красного цвета, которая выбрасывается сильной пульсирующей струёй.","Кровь тёмно-вишнёвого цвета, которая вытекает медленно, равномерной непрерывной струёй."],"c":0,"e":"<p>Кровотечение поверхностное, кровь по цвету близка к артериальной, выглядит как насыщенно-красная жидкость. Кровь вытекает в небольшом объёме, медленно.<br> Так называемый симптом «кровавой росы», кровь появляется на поражённой поверхности медленно в виде небольших, медленно растущих капель, напоминающих капли росы или конденсата.</p>","image":"assets/adrive-questions/q701000103.jpg"},{"id":701000201,"themeId":16,"group":7010002,"chapter":59,"chapters":[59],"q":"Что необходимо предпринять для остановки артериального кровотечения у пострадавшего?","a":["Наложить давящую повязку.","Наложить пращевидную повязку.","Наложить жгут ниже места повреждения.","Наложить жгут выше места повреждения.","Наложить согревающий компресс, обеспечить покой."],"c":3,"e":"<p>Оказание первой помощи необходимо начать с пережатия сосуда выше места повреждения.</p> <p>Далее накладывают жгут, который оставляют на конечности максимум на 1 час (зимой — 30 минут) у взрослых и на 25–30 (зимой — 10–15) минут — у детей.</p> <p>При артериальном кровотечении жгут накладывается выше места повреждения.</p> <p>Необходимо при накладывании жгута положить записку с временем наложения, и обязательно накладывать жгут на ткань во избежание пережатия конечности. Для этого можно использовать одежду пострадавшего.</p> <p>Если держать дольше, может наступить омертвление тканей.</p>","image":null},{"id":701000202,"themeId":16,"group":7010002,"chapter":59,"chapters":[59],"q":"Как правильно остановить венозное кровотечение у пострадавшего?","a":["Наложить давящую повязку.","Наложить спиральную повязку.","Наложить колосовидную повязку.","Наложить жгут выше места повреждения.","Пережать сосуд пальцами выше места повреждения."],"c":0,"e":"<p>При венозном кровотечении необходимо наложить стерильную тугую давящую повязку на рану. Зафиксировать в приподнятом положении повреждённую конечность.</p> <p>При сильном кровотечении прижать кровоточащую вену ниже места кровотечения.</p>","image":null},{"id":701000203,"themeId":16,"group":7010002,"chapter":59,"chapters":[59],"q":"Что необходимо сделать для остановки капиллярного кровотечения?","a":["Наложить на рану давящую повязку.","Наложить жгут выше раны на 15–20 см на подкладочный материал.","Максимально согнуть конечность и зафиксировать её в таком положении."],"c":0,"e":"<p>Остановка кровотечения проводится с помощью тугого бинтования.</p> <p>При адекватной свертывающей способности крови свертывание проходит самостоятельно без медицинской помощи.</p>","image":null},{"id":701000261,"themeId":16,"group":7010002,"chapter":59,"chapters":[59],"q":"В каком месте правильно накладывать кровоостанавливающий жгут на конечность при артериальном кровотечении?","a":["Выше раны на 10–15 сантиметров.","Ниже раны на 10–15 сантиметров.","Непосредственно на рану."],"c":0,"e":"<p>При артериальном кровотечении правильно накладывать кровоостанавливающий жгут на конечность выше раны на 10–15 сантиметров.</p>","image":"assets/adrive-questions/q701000261.jpg"},{"id":701000301,"themeId":16,"group":7010003,"chapter":59,"chapters":[59],"q":"Что из перечисленного ниже является способом остановки кровотечения?","a":["Наложение давящей повязки.","Пальцевое надавливание на сосуды.","Максимальное сгибание конечности.","Наложение кровоостанавливающего жгута.","Всё вышеперечисленное."],"c":4,"e":"<p>Временные способы остановки:</p> <ul><li>жгут (зимой: ребёнок — на 10–15 минут, взрослые — не более чем на 30 минут; летом: ребёнок и пенсионеры — на 25–30 минут, взрослые — до 1 часа).<br> При артериальном кровотечении жгут накладывается выше места повреждения.<br> Необходимо при накладывании жгута положить записку с временем наложения, и обязательно накладывать жгут на ткань во избежание пережатия конечности. Для этого можно использовать одежду пострадавшего;</li> <li>пальцевое прижатие — внешнее;</li> <li>максимальное сгибание конечности — внешнее;</li> <li>прикладывание льда — внешнее;</li> <li>поставить тампон — внутреннее.</li></ul>","image":null},{"id":701000401,"themeId":16,"group":7010004,"chapter":59,"chapters":[59],"q":"В каком месте необходимо придавить пальцем повреждённую артерию при артериальном кровотечении в области коленного сустава?","a":["В паховой области.","На коленном суставе.","На голеностопном суставе."],"c":0,"e":"<p>Кровотечение в области коленного сустава вызвано повреждением бедренной артерии. Бедренная артерия, a. femoralis, является продолжением наружной подвздошной артерии и начинается под паховой связкой в сосудистой лакуне.<br> Поэтому для остановки кровотечения необходимо придавить пальцем повреждённую артерию в паховой области.</p>","image":null},{"id":701000402,"themeId":16,"group":7010004,"chapter":59,"chapters":[59],"q":"В каком месте необходимо провести надавливание для остановки кровотечения при ранении или разрыве сонной артерии?","a":["Ниже раны.","Выше раны.","На самой ране."],"c":0,"e":"<p>Сонная артерия поднимается кверху и снабжает кровью части головы и шеи, поэтому для остановки кровотечения при ранении или разрыве артерии необходимо провести надавливание ниже раны (ближе к сердцу).</p>","image":null},{"id":701000403,"themeId":16,"group":7010004,"chapter":59,"chapters":[59],"q":"Что необходимо сделать для остановки кровотечения из раны в подмышечной области?","a":["Выпрямленную руку прибинтовать к туловищу.","На рану положить давящую повязку и руку, согнутую в локте, прибинтовать к туловищу.","Положить в подмышечную область валик, после чего прибинтовать выпрямленную руку к туловищу."],"c":1,"e":"<p>Для остановки кровотечения из раны в подмышечной области необходимо на рану положить давящую повязку и прибинтовать к туловищу руку, согнутую в локте.</p>","image":null},{"id":701001101,"themeId":16,"group":7010011,"chapter":59,"chapters":[59],"q":"Как правильно производить наложение кровоостанавливающего жгута на повреждённую конечность?","a":["Жгут накладывается непосредственно на рану.","Жгут накладывается на 10–15 см выше места повреждения непосредственно на кожу.","Жгут накладывается на 10–15 см ниже места повреждения на подкладочный материал.","Жгут накладывается на 10–15 см выше места повреждения на подкладочный материал.","Жгут накладывается на 10–15 см выше места повреждения, конечность фиксируется повязкой."],"c":3,"e":"<p>Жгут должен быть наложен выше места повреждения на подкладочный материал, чтобы прижимать крупный сосуд к костным выступам.</p> <p>Не следует накладывать жгут на среднюю треть плеча и верхней трети бедра, это с высокой вероятностью приведёт к повреждению нервных стволов, и будет неэффективно в плане остановки кровотечения.</p>","image":null},{"id":701001102,"themeId":16,"group":7010011,"chapter":59,"chapters":[59],"q":"В какой момент следует прекратить затяжку жгута при остановке кровотечения?","a":["С началом вдавливания жгута в тело.","В момент прекращения кровотечения.","При болезненном реагировании пострадавшего.","В момент начала ослабления интенсивности кровотечения."],"c":1,"e":"<p>Жгут накладывают только до остановки кровотечения.</p> <p>При болезненном реагировании пострадавшего жгут при возможности стоит переставить.</p>","image":null},{"id":701001103,"themeId":16,"group":7010011,"chapter":59,"chapters":[59],"q":"Как проверить, что кровоостанавливающий жгут наложен правильно?","a":["Конечность бледнеет, пульс прощупывается.","Развивается отёк, кожа приобретает багрово-синюшную окраску, появляются пузыри, наполненные жидкостью.","Кровотечение прекращается, конечность бледнеет, пульс не прощупывается, теряется чувствительность конечности."],"c":2,"e":"<p>Кровоостанавливающий жгут наложен правильно, когда прекращается кровотечение, конечность бледнеет, пульс не прощупывается, теряется чувствительность конечности.</p>","image":null},{"id":701001104,"themeId":16,"group":7010011,"chapter":59,"chapters":[59],"q":"На какое время может быть наложен кровоостанавливающий жгут?","a":["Не более 1 часа.","Не более 3 часов.","Не более 4 часов."],"c":0,"e":"<p>Согласно приказа Министерства Здравоохранения Республики Беларусь «Об утверждении клинического протокола об оказании скорой (неотложной) медицинской помощи…» №1030 от 30.09.2010 жгут может накладываться не более 1 часа при крайней необходимости.<br> При превышении указанного времени жгут нужно раскрутить на 5–10 минут, крепко прижать рану ладонью через повязку.</p> <p>Ослабление жгута необходимо повторять каждые полчаса.</p>","image":null},{"id":701001201,"themeId":16,"group":7010012,"chapter":59,"chapters":[59],"q":"Какие сведения должны быть указаны в записке, которая прикрепляется к жгуту, используемому для остановки кровотечения?","a":["Адрес пострадавшего.","Время наложения жгута.","Фамилия пострадавшего.","Место работы пострадавшего.","Фамилия и адрес лица, наложившего жгут."],"c":1,"e":"<p>При использовании жгута или закрутки под них нужно обязательно положить записку, где точно по часам указать время, когда они были наложены, чтобы медицинский работник знал, сколько времени прошло с момента прекращения кровотечения.</p> <p>Если оставить жгут (нарушить кровоснабжение) на длительное время, то может наступить омертвение тканей вследствие нарушения питания (ишемия участков тела ниже места наложения с последующей их гибелью).</p>","image":null},{"id":701001202,"themeId":16,"group":7010012,"chapter":59,"chapters":[59],"q":"Для чего после остановки кровотечения к жгуту прикрепляется записка?","a":["В записке указывается время наложения жгута.","В записке указываются повреждения, обнаруженные у пострадавшего.","В записке указываются место аварии и фамилия лица, наложившего жгут."],"c":0,"e":"<p>При использовании жгута или закрутки под них нужно обязательно положить записку, где точно по часам указать время, когда они были наложены, чтобы медицинский работник знал, сколько времени прошло с момента прекращения кровотечения.</p> <p>Если оставить жгут (нарушить кровоснабжение) на длительное время, то может наступить омертвение тканей вследствие нарушения питания (ишемия участков тела ниже места наложения с последующей их гибелью).</p>","image":null},{"id":701001301,"themeId":16,"group":7010013,"chapter":59,"chapters":[59],"q":"В каком случае на туловище пострадавшего накладывается жгут?","a":["В случае внутреннего кровотечения.","В случае повреждения внутренних органов.","При обильном кровотечении и обширном ранении.","На туловище жгут не накладывается."],"c":3,"e":"<p>Жгут накладывается на те части тела, где имеется возможность остановки кровотечения из артерий.</p>","image":"assets/adrive-questions/q701001301.jpg"},{"id":701002101,"themeId":16,"group":7010021,"chapter":59,"chapters":[59],"q":"С чего начинается оказание первой помощи при дорожно-транспортном происшествии после проведения первичного осмотра пострадавшего?","a":["С реанимационных действий.","С фиксации переломов и ушибов.","С остановки наружного кровотечения.","С выведения пострадавшего из бессознательного состояния."],"c":2,"e":"<p>При дорожно-транспортном происшествии необходимо в первую очередь остановить массивное кровотечение, так как потеря большого количества крови может привести к летальному исходу в короткое время.</p>","image":null},{"id":701002102,"themeId":16,"group":7010021,"chapter":61,"chapters":[61],"q":"Какая из перечисленных последовательностей проведения действий по оказанию первой помощи пострадавшему является правильной?","a":["Остановить наружное кровотечение, устранить причины нарушения дыхания, наложить на раны повязки, наложить шины.","Провести искусственное дыхание, остановить наружное кровотечение, наложить на раны повязки, наложить шины.","Провести искусственное дыхание, остановить наружное кровотечение, наложить шины, наложить повязки на раны."],"c":0,"e":"<p>Последовательность действий при оказании первой помощи пострадавшему, если у него имеется наружное кровотечение, угрожающее жизни, нарушено дыхание, имеются переломы конечностей и раны:</p> <ul><li>остановить наружное кровотечение;</li> <li>устранить причины нарушения дыхания;</li> <li>наложить на раны повязки;</li> <li>наложить шины.</li></ul> <p>Нарушения дыхания проявляются одышкой, слабым пульсом, спутанностью сознания, синюшностью кожных покровов и, в самых тяжёлых случаях, полным отсутствием дыхательных движений.</p> <p>Для устранения нарушений дыхания необходимо расстегнуть ворот, ослабить пояс, снять верхнюю одежду, пальцем освободить полость рта от инородных тел, восстановить проходимость воздуха через нос, удалив инородные тела, при проникающих ранениях грудной клетки на грудь пострадавшего наложить герметическую повязку, пострадавшему, находящемуся в бессознательном состоянии, сохранить проходимость воздухоносных путей, уложив на бок, в случае необходимости (при отсутствии самостоятельных дыхательных движений) произвести искусственное дыхание и непрямой массаж сердца.</p>","image":null},{"id":701002201,"themeId":16,"group":7010022,"chapter":59,"chapters":[59],"q":"Какая минимальная кровопотеря при остром кровотечении у пострадавшего является смертельной?","a":["1.5 литра.","2 литра.","2.5 литра."],"c":0,"e":"<p>При дорожно-транспортном происшествии необходимо в первую очередь остановить кровотечение, так как потеря большого количества крови может привести к летальному исходу в короткое время.<br> Кровопотеря более 1.5 литра крови при остром кровотечении у пострадавшего может быть смертельной.</p>","image":"assets/adrive-questions/q701002201.jpg"},{"id":701002202,"themeId":16,"group":7010022,"chapter":59,"chapters":[59],"q":"Через какое время при артериальном кровотечении может наступить смерть пострадавшего?","a":["Через 7–10 минут.","Через 30–40 минут.","Не ранее чем через 1 час."],"c":0,"e":"<p>Смерть пострадавшего при артериальном кровотечении может наступить через 7–10 минут, так как кровопотеря более 1.5 литра крови при остром кровотечении у пострадавшего является смертельной.</p>","image":"assets/adrive-questions/q701002202.jpg"},{"id":701003101,"themeId":16,"group":7010031,"chapter":60,"chapters":[60],"q":"Как правильно оказать первую помощь при обмороке?","a":["Пострадавшего уложить, согреть, напоить горячим напитком.","Перенести пострадавшего в прохладное место, уложить, охлаждать голову и область сердца, напоить холодным напитком.","Пострадавшего уложить, приподняв ноги, обеспечить приток свежего воздуха, дать понюхать нашатырный спирт, побрызгать в лицо холодной водой."],"c":2,"e":"<p>Если человек уже находится в состоянии обморока (приступ кратковременной утраты сознания, обусловленный временным нарушением мозгового кровотока), следует уложить его на ровную поверхность, подложив что-нибудь под ноги. Обязательно нужно ослабить застёжки, ремни, галстук ― всё, что сжимает тело, ― и обеспечить поступление свежего воздуха. <br>Нельзя обступать пострадавшего плотным кольцом ― это снижает приток кислорода.</p> <p>Далее нужно повернуть голову пострадавшего набок, чтобы избежать удушья в случае возникновения рвоты.</p> <p>После необходимо вызвать раздражение рецепторов кожи и слизистых. Лучше всего поднести к носу ватку или бинт, смоченные нашатырным спиртом. Нельзя подносить спирт прямо в ёмкости ― это может вызвать ожоги слизистой.<br> Если нашатыря нет под рукой, можно просто пощекотать нос тем же бинтом или травинкой; похлопать человека по щекам; побрызгать холодной водой; растереть ему виски.</p> <p>Если человек не приходит в сознание несколько минут, нужно вызывать «скорую помощь».</p>","image":null},{"id":701003201,"themeId":16,"group":7010032,"chapter":60,"chapters":[60],"q":"Что из перечисленного ниже может явиться причиной возникновения травматического шока?","a":["Тяжёлая травма.","Обширные ожоги.","Значительная кровопотеря.","Всё перечисленное."],"c":3,"e":"<p>Истинной причиной развития травматического шока является быстрая потеря большого объёма крови или плазмы. Причём эта потеря не обязана быть в виде явного (наружного) или скрытого (внутреннего) кровотечения — шоковое состояние может вызывать и массивная экссудация плазмы через обожжённую поверхность кожи при ожогах.</p> <p>Сильная боль, а также нервно-психический стресс, связанный с травмой, несомненно, играют роль в развитии шокового состояния (хотя и не являются его главной причиной) и усугубляют тяжесть шока.</p>","image":null},{"id":701003202,"themeId":16,"group":7010032,"chapter":60,"chapters":[60],"q":"Как правильно оказать первую помощь с целью профилактики возникновения травматического шока у пострадавшего?","a":["Как можно скорее устранить причину, которая может вызвать травматический шок (остановить кровотечение, иммобилизовать переломы), пострадавшего уложить, согреть, напоить горячим напитком (при отсутствии травмы живота).","Вынести пострадавшего на чистый воздух, побрызгать в лицо холодной водой.","Перенести пострадавшего в прохладное место, уложить, охлаждать голову и область сердца с помощью холодных компрессов."],"c":0,"e":"<p>Основное мероприятие первой помощи при травматическом шоке — остановка кровотечения.<br> При низкой температуре воздуха также стоит укрыть пострадавшего, чтобы предотвратить переохлаждение.</p> <p>Необходимо обеспечить скорейшее оказание пострадавшему квалифицированной медицинской помощи, вызвав «скорую помощь» или доставив пострадавшего в медицинское учреждение.</p> <p>Если у пострадавшего нет травм и повреждений, используют противошоковую позицию: пострадавший лежит на спине, ноги подняты на 15–30 см, также необходимо согреть и напоить горячим напитком.</p>","image":null},{"id":701004101,"themeId":16,"group":7010041,"chapter":60,"chapters":[60],"q":"Какие характерные симптомы наблюдаются у пострадавшего при сотрясении головного мозга?","a":["Похолодание тела, потеря сознания.","Деформация черепа, очковая гематома.","Головная боль, тошнота, слабость, потеря сознания."],"c":2,"e":"<p>При травме, сопровождающейся сотрясением головного мозга, возможна потеря сознания длительностью до 5 минут. После возвращения сознания больные могут жаловаться на головную боль, головокружение, тошноту, часто — рвоту, шум в ушах, потливость, нарушение сна.<br> Жизненно важные функции — без значимых отклонений.</p> <p>В неврологическом статусе можно отметить преходящие микросимптомы (рефлекс Бабинского, нистагм, преходящая анизорефлексия).</p>","image":null},{"id":701004201,"themeId":16,"group":7010042,"chapter":60,"chapters":[60],"q":"Какие из перечисленных признаков являются характерными для организма в состоянии клинической смерти?","a":["Остановка дыхания, бледность.","Потеря сознания, наличие пульса в артериях.","Потеря сознания, отсутствие пульса, остановка дыхания."],"c":2,"e":"<p>Клиническая смерть — обратимый этап умирания, переходный период между жизнью и биологической смертью. На данном этапе прекращается деятельность сердца и процесс дыхания, полностью исчезают все внешние признаки жизнедеятельности организма.</p> <p>При этом гипоксия (кислородное голодание) не вызывает необратимых изменений в наиболее к ней чувствительных органах и системах.</p> <p>Данный период терминального состояния, за исключением редких и казуистических случаев, в среднем продолжается не более 3–4 минут, максимум 5–6 минут (при исходно пониженной или нормальной температуре тела).</p>","image":null},{"id":701004202,"themeId":16,"group":7010042,"chapter":61,"chapters":[61],"q":"Какова последовательность действий при оказании первой помощи пострадавшему при отсутствии у пострадавшего дыхания и остановке сердца?","a":["Освободить дыхательные пути, провести непрямой массаж сердца и искусственное дыхание.","Освободить дыхательные пути, провести искусственное дыхание, дать понюхать нашатырный спирт.","Провести непрямой массаж сердца, затем освободить дыхательные пути и провести искусственное дыхание."],"c":0,"e":"<p>Согласно Клинического протокола (Приложение 1 к Постановлению Министерства здравоохранения Республики Беларусь от 06.06.2017 № 59) перед сердечно-лёгочной реанимацией (СЛР) необходимо проверить / обеспечить проходимость дыхательных путей.</p> <p>Далее провести СЛР по алгоритму:</p> <ol><li>Начать СЛР с непрямого массажа сердца компрессией грудной клетки: <ul><li>обеспечить экскурсию грудной клетки на 4–5 см;</li> <li>число компрессий должно составлять не менее 100 в минуту.</li></ul></li> <li>После проведения цикла из 30 компрессий грудной клетки выполнить 2 вдоха искусственного дыхания (соотношение 30:2 сохраняется на протяжении всех реанимационных мероприятий независимо от количества человек, оказывающих помощь).</li></ol>","image":null},{"id":701004301,"themeId":16,"group":7010043,"chapter":61,"chapters":[61],"q":"Что необходимо предпринять, если у пострадавшего отсутствует дыхание?","a":["Провести массаж сердца.","Провести искусственное дыхание.","Уложить на спину и дать понюхать нашатырный спирт."],"c":1,"e":"<p>Частота вдыханий воздуха при искусственном дыхании должна быть примерно 12–16 раз в минуту.</p> <p>Чаще всего при остановке дыхания останавливается и сердце. В этом случае нужно также делать непрямой массаж сердца.</p>","image":null},{"id":701004302,"themeId":16,"group":7010043,"chapter":61,"chapters":[61],"q":"Какая частота вдыханий воздуха должна быть при проведении искусственного дыхания?","a":["5–10 раз в минуту.","12–16 раз в минуту.","20–25 раз в минуту."],"c":1,"e":"<p>Среди предложенных вариантов ответов наиболее правильным является ответ: 12–16 раз в минуту, что обусловлено характером проводимого реанимационного мероприятия.</p>","image":null},{"id":701004401,"themeId":16,"group":7010044,"chapter":61,"chapters":[61],"q":"В каком месте необходимо проводить массаж сердца?","a":["На верхней части грудины.","На грудной клетке с левой стороны.","На границе средней и нижней трети грудины."],"c":2,"e":"<p>Массаж сердца необходимо проводить на границе средней и нижней трети грудины.</p> <p>Алгоритм действий следующий:</p> <ul><li>Пострадавшего укладывают на спину, обязательно на жёсткую поверхность. Если он лежит на кровати, его следует переложить на пол.</li> <li>Спасатель стоит (в полный рост или на коленях) сбоку от пострадавшего. Одну ладонь он кладёт на нижнюю половину грудины (на границе средней и нижней трети грудины) больного так, чтобы пальцы были ей перпендикулярны. Поверх помещают другую руку. Приподнятые пальцы не касаются тела. Прямые руки спасателя располагаются перпендикулярно грудной клетке пострадавшего.</li> <li>Массаж производят быстрыми толчками, тяжестью всего тела, не сгибая руки в локтях. Грудина больного при этом должна прогибаться на одну треть (около 5 см для взрослого пострадавшего).</li></ul>","image":null},{"id":701004402,"themeId":16,"group":7010044,"chapter":61,"chapters":[61],"q":"Как оказать помощь пострадавшему при остановке сердца?","a":["Провести массаж сердца.","Провести искусственное дыхание.","Уложить на спину и дать понюхать нашатырный спирт.","Провести массаж сердца одновременно с искусственным дыханием."],"c":3,"e":"<p>При остановке сердца проводится непрямой массаж сердца совместно с искусственной вентиляцией лёгких до прибытия скорой помощи или появления признаков биологической смерти.<br> Такой комплекс мер первой помощи называется сердечно-лёгочной реанимацией.</p>","image":null},{"id":701004501,"themeId":16,"group":7010045,"chapter":61,"chapters":[61],"q":"Какое правильное соотношение при выполнении реанимации (оживлении) между непрямым массажем сердца и искусственным дыханием, если первую помощь оказывают два человека?","a":["После 2–3 вдуваний воздуха 10 раз надавливать на грудную клетку в области сердца и так далее.","После 30 надавливаний на грудную клетку на границе средней и нижней части грудины сделать 2 искусственных вдоха, независимо от количества реаниматоров.","Один раз надавливать на грудную клетку в области сердца, затем один раз вдувать воздух и так далее."],"c":1,"e":"<p>При остановке дыхания и (или) кровообращения проводят сердечно-лёгочную реанимацию согласно действующим нормативным документам и вызывают реанимационную бригаду.</p> <p>Сердечно-лёгочная реанимация начинается с проведения закрытого массажа сердца. Компрессия грудной клетки (непрямой массаж сердца) с частотой 100–120 раз в минуту на глубину 5–6 см, детям — 100 раз в минуту на глубину до 5 см. Соотношение вдохов к компрессии — 2:30.</p> <p>Соотношение не зависит от количества человек, которые делают реанимацию.</p>","image":null},{"id":701004502,"themeId":16,"group":7010045,"chapter":61,"chapters":[61],"q":"Как правильно выполнить непрямой массаж сердца и искусственное дыхание, если оживление (реанимацию) проводит один человек?","a":["Сделать 1 искусственный вдох, затем 5 раз надавливать на грудную клетку.","Сделать 5 искусственных вдохов, затем 20 раз надавливать на грудную клетку.","Сделать 30 надавливаний на грудную клетку на границе средней и нижней части грудины, затем 2 искусственных вдоха, независимо от количества реаниматоров."],"c":2,"e":"<p>При остановке дыхания и (или) кровообращения проводят сердечно-лёгочную реанимацию согласно действующим нормативным документам и вызывают реанимационную бригаду.</p> <p>Сердечно-лёгочная реанимация начинается с проведения закрытого массажа сердца. Компрессия грудной клетки (непрямой массаж сердца) с частотой 100–120 раз в минуту на глубину 5–6 см, детям — 100 раз в минуту на глубину до 5 см. Соотношение вдохов к компрессии — 2:30.</p> <p>Соотношение не зависит от количества человек, которые делают реанимацию.</p>","image":null},{"id":701005101,"themeId":16,"group":7010051,"chapter":63,"chapters":[63],"q":"Как правильно оказать первую помощь при термическом ожоге?","a":["Наложить тёплый компресс.","Наложить холодный компресс.","Приложить на повреждённое место салфетку с аммиаком.","Наложить сухую стерильную бинтовую повязку.","Обработать повреждённое место перекисью водорода."],"c":3,"e":"<p>Прекратить действие термического агента на кожу. Для этого пострадавшего надо вывести из огня, потушить горящую одежду, прекратить контакт с раскалёнными предметами, жидкостями, паром и тому подобным. Чем быстрее это сделано, тем меньше будет глубина ожога.</p> <p>Далее необходимо охладить обожжённые участки. Так как обожжённые ткани нагреты до высокой температуры под действием термического агента, даже после его устранения они сами воздействуют на подлежащие ткани как термический агент, поэтому их необходимо как можно быстрее охладить с помощью холодной воды или пузырей со льдом в течение 10–15 минут.</p> <p>Далее наложить асептическую повязку. Для этого одежду с обожжённых участков аккуратно срезают. Ни в коем случае нельзя пытаться очищать обожжённые области (снимать приставшие к коже обрывки одежды, смолу, битум и тому подобное), а также вскрывать пузыри. Не рекомендуется смазывать обожжённые участки растительными и животными жирами, растворами марганцевокислого калия или бриллиантового зелёного и тому подобным.</p> <p>На ожоговые раны без предварительной обработки накладывают сухие асептические повязки.</p>","image":null},{"id":701005171,"themeId":16,"group":7010051,"chapter":63,"chapters":[63],"q":"Допускается ли использовать индивидуальный медицинский перевязочный пакет, входящий в состав автомобильной медицинской аптечки, для закрытия ожоговой поверхности?","a":["Да, допускается.","Нет, не допускается."],"c":0,"e":"<p>Пакет перевязочный медицинский индивидуальный стерильный <strong>используется для перевязки открытых ран, закрытия ожогов</strong>. Вскрывают упаковку, извлекают и расправляют пакет, накладывают на поврежденную поверхность и фиксируют бинтом.</p>","image":"assets/adrive-questions/q701005171.jpg"},{"id":701005201,"themeId":16,"group":7010052,"chapter":63,"chapters":[63],"q":"Как правильно проводить тушение пламени при возгорании одежды у пострадавшего?","a":["Катать пострадавшего по земле с целью сбить пламя.","Тушить одежду на пострадавшем при помощи огнетушителя.","Облить пострадавшего холодной водой или обсыпать песком.","Обернуть пострадавшего одеялом или покрывалом, затем облить его водой."],"c":3,"e":"<p>При возгорании одежды у пострадавшего необходимо для тушения пламени обернуть пострадавшего одеялом или покрывалом (это позволит нарушить доступ воздуха к области горения), затем облить его водой.</p>","image":null},{"id":701005202,"themeId":16,"group":7010052,"chapter":63,"chapters":[63],"q":"Что при оказании помощи необходимо выполнить, если у пострадавшего сгоревшая одежда пристала к ожоговой поверхности тела?","a":["Смыть остатки одежды холодной водой.","Смыть остатки одежды холодной водой с мылом.","Удалить остатки одежды с помощью тампона, смоченного в растворе перекиси водорода.","Не удаляя остатков одежды, наложить сухую стерильную повязку на ожоговую поверхность."],"c":3,"e":"<p>Одежду с обожжённых участков аккуратно срезают.</p> <p>Ни в коем случае нельзя пытаться очищать обожжённые области (снимать приставшие к коже обрывки одежды, смолу, битум и тому подобное), а также вскрывать пузыри.</p>","image":null},{"id":701005301,"themeId":16,"group":7010053,"chapter":63,"chapters":[63],"q":"Какую первую помощь необходимо оказать пострадавшему при химическом ожоге?","a":["Обработать рану перекисью водорода, наложить стерильную повязку.","Обильно промыть место ожога холодной водой, наложить стерильную повязку.","Промыть обожжённые участки перекисью водорода, наложить стерильную повязку."],"c":1,"e":"<p>Для избавления от воздействующих на кожный покров причин химического ожога следует смыть химические вещества с него с помощью проточной воды.</p> <p>При наличии такой возможности область поражения под струёй воды необходимо продержать порядка от 15 минут и более.<br> Если же не было произведено своевременное устранение воздействующего компонента, то длительность последующего промывания должна составить от получаса и более.</p> <p>После промывания на поражённый участок необходимо наложить сухую стерильную повязку.</p>","image":null},{"id":701005302,"themeId":16,"group":7010053,"chapter":63,"chapters":[63],"q":"Что необходимо предпринять при попадании в глаза электролита из аккумуляторной батареи?","a":["Промыть глаза мыльной водой.","Промыть глаза спиртосодержащим раствором.","Промыть глаза слабым раствором питьевой соды.","Промыть глаза струёй воды в течение нескольких минут."],"c":3,"e":"<p>Для избавления от воздействующих на кожный покров причин химического ожога следует смыть химические вещества с него с помощью проточной воды.</p>","image":null},{"id":701005303,"themeId":16,"group":7010053,"chapter":63,"chapters":[63],"q":"Как правильно оказать помощь пострадавшему при попадании серной кислоты на незащищённый участок кожного покрова?","a":["Наложить холодный компресс.","Наложить асептическую повязку.","Промыть поражённый участок автомобильным шампунем.","Промыть поражённый участок обильным количеством воды и наложить сухую стерильную повязку."],"c":3,"e":"<p>Для избавления от воздействующих на кожный покров причин химического ожога следует смыть химические вещества с него с помощью проточной воды.</p> <p>При наличии такой возможности область поражения под струёй воды необходимо продержать порядка от 15 минут и более.<br> Если же не было произведено своевременное устранение воздействующего компонента, то длительность последующего промывания должна составить от получаса и более.</p> <p>После промывания на поражённый участок необходимо наложить сухую стерильную повязку.</p>","image":null},{"id":701006101,"themeId":16,"group":7010061,"chapter":64,"chapters":[64],"q":"Какие из перечисленных признаков являются характерными симптомами вывиха?","a":["Боль в конечности, общая слабость.","Боль в конечности, отёк, патологическая подвижность.","Боль в конечности, деформация области сустава, отсутствие движения в суставе."],"c":2,"e":"<p>К основным симптомам вывиха можно отнести:</p> <ul><li>появление резкой боли в повреждённом суставе при пальпации или попытке совершить движение — первый признак вывиха;</li> <li>деформация сустава, видимое изменение его формы и размера;</li> <li>появление припухлости и покраснения кожи вокруг самого сустава;</li> <li>при повреждении нерва может отсутствовать чувствительность.</li></ul>","image":null},{"id":701006201,"themeId":16,"group":7010062,"chapter":64,"chapters":[64],"q":"Разрешается ли вправить вывих пострадавшему при оказании первой помощи?","a":["Запрещается.","Разрешается, если отёк ещё не наступил.","Разрешается, если пострадавший не ощущает боль."],"c":0,"e":"<p>Ни в коем случае не нужно пытаться вправить вывих самостоятельно, это под силу лишь опытному врачу.</p>","image":null},{"id":701006202,"themeId":16,"group":7010062,"chapter":64,"chapters":[64],"q":"Что необходимо сделать при вывихе конечности у пострадавшего?","a":["Вправить вывих.","Наложить шину, как и при переломах.","Наложить тугую повязку на место вывиха."],"c":1,"e":"<p>Оказание помощи при вывихе:</p> <ol><li>холод на область повреждённого сустава;</li> <li>применение обезболивающих средств;</li> <li>иммобилизация конечности в том положении, которое она приняла после травмы;</li> <li>обратиться к хирургу.</li></ol>","image":null},{"id":701006301,"themeId":16,"group":7010063,"chapter":64,"chapters":[64],"q":"Как оказать первую помощь при вывихе плечевого сустава?","a":["Вправить вывих.","Обеспечить полную неподвижность сустава.","Растереть место вывиха жёстким материалом и забинтовать."],"c":1,"e":"<p>Необходимо обеспечить полную неподвижность сустава, подвесив руку на косыночной повязке.</p> <p>Косынка представляет собой отрезок ткани со связанными концами, надеваемый на шею и поддерживающий повреждённую руку.</p>","image":null},{"id":701007102,"themeId":16,"group":7010071,"chapter":64,"chapters":[64],"q":"При ушибах конечностей необходимо:","a":["Наложить шину.","Применить согревающий компресс.","Обеспечить покой, к ушибленному суставу приложить холод."],"c":2,"e":"<p>При ушибе нужно приложить к больному месту холод. Это позволит уменьшить отёк или гематому за счёт сужения сосудов.</p> <p>Обеспечить ушибленной конечности покой.</p>","image":null},{"id":701007201,"themeId":16,"group":7010072,"chapter":64,"chapters":[64],"q":"Что необходимо сделать при ушибе мягких тканей бедра?","a":["Растереть место ушиба, затем зафиксировать место ушиба тугой повязкой, пострадавшему обеспечить покой.","Зафиксировать место ушиба тугой повязкой, к ушибу приложить грелку, дать пострадавшему обезболивающее.","Зафиксировать место ушиба тугой повязкой, область ушиба охладить в течение 10–15 минут, а конечности придать возвышенное положение."],"c":2,"e":"<p>Первая помощь при ушибе мягких тканей бедра:</p> <ul><li>Прекратить физические нагрузки, опору на ногу.</li> <li>Перебинтовать место ушиба тугой повязкой, эластичным бинтом, следя, чтобы сохранялась чувствительность и не синели кожные покровы ниже наложения бинта.</li> <li>Приложить к месту ушиба холод (лёд в пакете, холодную воду в бутылке) на 10–15 минут, в течение первого часа повторить ещё 2 раза.</li> <li> Придать конечности возвышенное положение.</li> <li>При выраженной боли принять обезболивающий препарат.</li> <li>В ближайшие часы обратиться к врачу, чтобы исключить осложнения и другие травмы.</li></ul>","image":null},{"id":701007302,"themeId":16,"group":7010073,"chapter":67,"chapters":[67],"q":"Какую помощь необходимо оказать пострадавшему при ушибе живота?","a":["Смазать место ушиба перекисью водорода.","Растереть место ушиба жёстким материалом, наложить повязку, дать обильное питьё.","Обеспечить пострадавшему полный покой, а область ушиба охладить (гипотермический пакет или пакет со снегом, льдом).","Массажировать область ушиба, а затем прогреть его (грелка, примочки с теплой водой)."],"c":2,"e":"<p>Первая помощь при сильных ушибах живота сводится к следующим действиям: необходимо уложить человека на спину, ноги при этом должны быть согнуты, на место ушиба наложить повязку, а область ушиба охладить (гипотермический пакет или пакет со снегом, льдом).</p> <p>Не давать пострадавшему ни пить, ни есть до приезда скорой помощи.</p>","image":null},{"id":701007303,"themeId":16,"group":7010073,"chapter":67,"chapters":[67],"q":"Разрешается ли давать пить пострадавшему с травмой живота?","a":["Разрешается, если пострадавший просит об этом.","Разрешается, при отсутствии открытой раны живота у пострадавшего.","Разрешается, но не ранее, чем через два часа после получения травмы.","Запрещается во всех случаях."],"c":3,"e":"<p>Первая помощь при сильных ушибах живота сводится к следующим действиям: необходимо уложить человека на спину, ноги при этом должны быть согнуты, на место ушиба наложить повязку, а область ушиба охладить (гипотермический пакет или пакет со снегом, льдом).</p> <p>Не давать пострадавшему ни пить, ни есть до приезда скорой помощи.</p>","image":null},{"id":701008101,"themeId":16,"group":7010081,"chapter":64,"chapters":[64],"q":"Какую первую помощь необходимо оказать при повреждении связок?","a":["Наложить жгут выше места повреждения.","Согреть повреждённый сустав, обеспечить покой.","Интенсивно растереть место повреждения, наложить тугую повязку.","Наложить повязку, фиксирующую сустав, прикладывать холодный компресс."],"c":3,"e":"<p>Первая помощь при повреждении связок:</p> <ul><li> Обеспечение покоя и неподвижности пострадавшему. Наложение повязки, фиксирующей сустав.<br> Пострадавшему следует принять удобное лежачее или сидячее положение, исключающее шевеления травмированной конечностью, и по возможности приподнять конечность во избежание нарастания отёка.</li> <li>Применение холода. Рекомендуется для снижения болевых ощущений и уменьшения отёка сразу после повреждения и в течение первого дня.<br> Кубики льда нужно насыпать в полиэтиленовый пакет или резиновую грелку, обернуть полотенцем и приложить к суставу на 15–20 мин. Процедуру можно повторять несколько раз с получасовыми перерывами.<br> Нельзя прикладывать лёд к голой коже или на длительное время, так как это может вызвать нарушение кровообращения.</li> <li>Предохранение от нагрузки. Поражённый сустав следует зафиксировать при помощи эластичного бинта или трубчатой компрессионной повязки из неопрена или эластика.</li> <li>Чтобы уменьшить боль и снять отёчность, в первые дни применяются мази или таблетки с противовоспалительными и обезболивающими компонентами.</li></ul>","image":null},{"id":701009102,"themeId":16,"group":7010091,"chapter":65,"chapters":[65],"q":"Для чего применяется входящий в состав автомобильной медицинской аптечки раствор 3% перекиси водорода?","a":["Для вдыхания при обмороке, угаре.","Как средство, успокаивающее боли в области сердца.","Для обработки раны при повреждении кожи и тканей.","Для смазывания кожи при химических ожогах первой степени."],"c":2,"e":"<p>Перекись водорода (раствор 3%) применяют как дезинфицирующее средство <strong>для промывания ран</strong>, для очистки поверхности кожи от крови.</p>","image":"assets/adrive-questions/q701009102.jpg"},{"id":701009171,"themeId":16,"group":7010091,"chapter":65,"chapters":[65],"q":"Может ли входящий в состав автомобильной медицинской аптечки раствор 3% перекиси водорода использоваться для промывания незначительных ран, порезов?","a":["Да, может.","Нет, он предназначен только для обработки кожи вокруг ран."],"c":0,"e":"<p>Перекись водорода раствор 3% применяют как дезинфицирующее средство <strong>для промывания ран</strong>, для очистки поверхности кожи от крови.</p>","image":"assets/adrive-questions/q701009171.jpg"},{"id":701009201,"themeId":16,"group":7010092,"chapter":65,"chapters":[65],"q":"Как правильно обработать рану?","a":["Промыть рану водой, удалить из раны крупные инородные предметы, наложить бинтовую повязку.","Промыть водой, удалить инородные предметы, обработать края раны раствором 3% перекиси водорода.","Обработать рану раствором 3% перекиси водорода, накрыть рану стерильной марлей и наложить бинтовую повязку."],"c":2,"e":"<p>Рану необходимо обработать раствором 3% перекиси водорода. При его отсутствии можно воспользоваться раствором 0.05% хлоргексидина биглюконата.</p> <p>Наложить повязку. Для остановки кровотечения, уменьшения припухлости (отёка) и создания покоя (например, повреждённой конечности) на область раны накладывают давящую повязку из бинта, чистой проглаженной несинтетической материи.</p>","image":null},{"id":701009202,"themeId":16,"group":7010092,"chapter":65,"chapters":[65],"q":"Как правильно оказать первую помощь пострадавшему при повреждении кожных покровов и мышечных тканей?","a":["Обработать рану раствором аммиака.","Не обрабатывая рану, наложить повязку.","Рану промыть, инородные тела извлечь, наложить повязку.","Обработать рану раствором 3% перекиси водорода, накрыть рану стерильным материалом и наложить повязку."],"c":3,"e":"<p>Рану необходимо обработать раствором 3% перекиси водорода. При его отсутствии можно воспользоваться раствором 0.05% хлоргексидина биглюконата.</p> <p>Наложить повязку. Для остановки кровотечения, уменьшения припухлости (отёка) и создания покоя (например, повреждённой конечности) на область раны накладывают давящую повязку из бинта, чистой проглаженной несинтетической материи.</p>","image":null},{"id":701009271,"themeId":16,"group":7010092,"chapter":65,"chapters":[65],"q":"Для чего предназначена марлевая медицинская салфетка, входящая в состав автомобильной медицинской аптечки?","a":["Только для закрытия раневой поверхности и наложения повязок.","Только для очистки кожи от загрязнения.","Для всего вышеперечисленного."],"c":2,"e":"<p>Салфетка марлевая медицинская стерильная размером не менее 10 х 10 см используется <strong>для закрытия раневой поверхности, наложения повязок, очистки кожи от загрязнения</strong>.</p> <p>В состав аптечки входит пять медицинских салфеток.</p>","image":"assets/adrive-questions/q701009271.jpg"},{"id":701009301,"themeId":16,"group":7010093,"chapter":65,"chapters":[65],"q":"Что необходимо сделать при загрязнении открытой раны землёй?","a":["Наложить на рану стерильную повязку.","Промыть рану раствором 3% перекиси водорода, наложить стерильную повязку.","Края раны обработать раствором 3% перекиси водорода, наложить давящую повязку."],"c":1,"e":"<p>Рану нужно тщательно промыть раствором 3% перекиси водорода.</p> <p>Если его недостаточно, а рана сильно загрязнена — промыть водой или слабым водным раствором марганцовки (2–3 крупинки на стакан воды, желательно кипячёной). Затем рану необходимо обработать раствором 3% перекиси водорода.</p> <p>Для исключения дальнейшего загрязнения, уменьшения припухлости (отёка) и создания покоя (например, повреждённой конечности) на область раны накладывают сухую стерильную повязку из бинта или чистой проглаженной несинтетической материи.</p>","image":null},{"id":701009302,"themeId":16,"group":7010093,"chapter":65,"chapters":[65],"q":"Как необходимо поступить при проникающем ранении крупными инородными предметами и наличии в ране мелких?","a":["Извлечь крупные инородные предметы, наложить стерильную повязку.","Обработать края раны раствором 3% перекиси водорода, извлечь мелкие инородные предметы, наложить стерильную повязку.","Обработать рану раствором 3% перекиси водорода, не извлекать инородные предметы, наложить стерильную повязку.","Туго забинтовать место повреждения."],"c":2,"e":"<p>Крупные или мелкие инородные предметы из раны ни в коем случае нельзя извлекать.</p> <p>Это объясняется тем, что как крупные, так и мелкие инородные предметы закрывают поражённые сосуды, оказывая на них пережимающее действие и предотвращая кровотечение. Извлечение этих предметов возможно только в больничных условиях, где медицинский работник сразу же сможет оказать необходимую помощь.</p> <p>Рану следует обработать раствором 3% перекиси водорода и наложить стерильную повязку.</p>","image":null},{"id":701010101,"themeId":16,"group":7010101,"chapter":65,"chapters":[65],"q":"Какие типы переломов не существуют?","a":["Скрытые.","Закрытые.","Открытые."],"c":0,"e":"<p>По целостности кожных покровов переломы бывают:</p> <ul><li>Закрытые — не сопровождаются ранениями тканей, проникающих к месту перелома, и не сообщаются с внешней средой.</li> <li>Открытые — (огнестрельные и неогнестрельные) переломы костей, сопровождающиеся ранениями мягких тканей и сообщающиеся с внешней средой.</li></ul>","image":null},{"id":701010102,"themeId":16,"group":7010101,"chapter":65,"chapters":[65],"q":"В каком из ответов наиболее точно перечислены предметы, которые можно использовать в качестве иммобилизирующих шин?","a":["Доски, картон, рейки, бинт.","Доски, палки, пучки прутьев.","Жгут кровоостанавливающий.","Только стандартные медицинские шины."],"c":1,"e":"<p>В качестве иммобилизующего средства (шины) можно использовать плоские узкие предметы: палки, доски, линейки, фанеру, пучки прутьев и подобное.</p>","image":null},{"id":701010103,"themeId":16,"group":7010101,"chapter":65,"chapters":[65],"q":"Как правильно зафиксировать шинами место перелома?","a":["Фиксируется один сустав, который ниже места перелома.","Фиксируется один сустав, который выше места перелома.","Фиксируются два сустава — выше и ниже места перелома."],"c":2,"e":"<p>Чтобы зафиксировать шинами место перелома, необходимо фиксировать два сустава — выше и ниже места перелома.</p>","image":null},{"id":701010201,"themeId":16,"group":7010102,"chapter":65,"chapters":[65],"q":"Укажите правильные признаки открытого перелома кости:","a":["Нарушение целостности кожных покровов, выступающие обломки кости.","На кожных покровах повреждения отсутствуют, имеется хорошо различимая деформация конечности.","На кожном покрове значительное повреждение, обильное кровотечение, деформация в области сустава отсутствует."],"c":0,"e":"<p>Открытые переломы — переломы костей, сопровождающиеся ранениями мягких тканей и сообщающиеся с внешней средой.</p>","image":null},{"id":701010202,"themeId":16,"group":7010102,"chapter":65,"chapters":[65],"q":"Как правильно оказать первую помощь при открытом переломе конечности?","a":["Туго перебинтовать повреждённую конечность.","Остановить кровотечение, наложить повязку на рану, зафиксировать конечность с помощью шин.","Совместить кости в месте перелома друг с другом, наложить повязку, зафиксировать конечность с помощью шины."],"c":1,"e":"<p>Основной алгоритм действий при оказании первой помощи при открытом переломе:</p> <ul><li>осмотр пострадавшего и оценка его состояния;</li> <li>при открытом переломе в первую очередь необходимо остановить кровотечение. Для этого необходимо: при артериальном кровотечении — наложить жгут на область выше раны, при венозном — наложить давящую повязку;</li> <li>дайте по возможности обезболивающий препарат для снятия острого болевого синдрома;</li> <li>обработайте раневую поверхность 3% раствором перекиси водорода, 5% спиртовым раствором йода, «Мирамистином» или любым другим антисептическим средством;</li> <li>осушите раневую поверхность при помощи стерильной марлевой салфетки;</li> <li>вскройте стерильный перевязочный пакет и наложите его без тугого накладывания бинта на раневую поверхность;</li> <li>подберите подходящие предметы для иммобилизации конечности (для этого можно использовать специальные шины, прямые палки, прутья, доски, пластиковые твёрдые предметы с ровной поверхностью), чтобы предупредить смещение отломков, снизить вероятность ранения костями мышц, сосудов, нервов и уменьшить опасность болевого шока;</li> <li>не исправляя положения конечности, прикладываются шины и прибинтовываются к ноге или руке таким образом, чтобы они были плотно зафиксированы;</li> <li>вызывается бригада скорой медицинской помощи.</li></ul>","image":null},{"id":701010203,"themeId":16,"group":7010102,"chapter":65,"chapters":[65],"q":"Что необходимо сделать при открытом переломе конечности и сильном кровотечении?","a":["Наложить жгут, повязку на рану, зафиксировать конечность с помощью шин.","Прибинтовать повреждённую конечность к туловищу, пострадавшего уложить на спину, обеспечить покой.","Наложить повязку на рану, конечность не фиксировать, пострадавшего уложить и накрыть пледом или одеялом."],"c":0,"e":"<p>Основной алгоритм действий при оказании первой помощи при открытом переломе:</p> <ul><li>осмотр пострадавшего и оценка его состояния;</li> <li>при открытом переломе в первую очередь необходимо остановить кровотечение. Для этого необходимо: при артериальном кровотечении — наложить жгут на область выше раны, при венозном — наложить давящую повязку;</li> <li>дайте по возможности обезболивающий препарат для снятия острого болевого синдрома;</li> <li>обработайте раневую поверхность 3% раствором перекиси водорода, 5% спиртовым раствором йода, «Мирамистином» или любым другим антисептическим средством;</li> <li>осушите раневую поверхность при помощи стерильной марлевой салфетки;</li> <li>вскройте стерильный перевязочный пакет и наложите его без тугого накладывания бинта на раневую поверхность;</li> <li>подберите подходящие предметы для иммобилизации конечности (для этого можно использовать специальные шины, прямые палки, прутья, доски, пластиковые твёрдые предметы с ровной поверхностью), чтобы предупредить смещение отломков, снизить вероятность ранения костями мышц, сосудов, нервов и уменьшить опасность болевого шока;</li> <li>не исправляя положения конечности, прикладываются шины и прибинтовываются к ноге или руке таким образом, чтобы они были плотно зафиксированы;</li> <li>вызывается бригада скорой медицинской помощи.</li></ul>","image":null},{"id":701010301,"themeId":16,"group":7010103,"chapter":65,"chapters":[65],"q":"Как оказать помощь при закрытом переломе конечности?","a":["Перевязать место перелома.","Помассировать место перелома.","Зафиксировать конечность при помощи шин или заменяющих их предметов."],"c":2,"e":"<p>Подобрать подходящие предметы для иммобилизации конечности (для этого можно использовать специальные шины, прямые палки, доски, пластиковые твёрдые предметы с ровной поверхностью).</p> <p>Не исправляя положения конечности, прикладываются шины и прибинтовываются к ноге или руке таким образом, чтобы они были плотно зафиксированы.</p> <p>Далее вызывается бригада скорой медицинской помощи.</p>","image":null},{"id":701011101,"themeId":16,"group":7010111,"chapter":65,"chapters":[65],"q":"Как необходимо накладывать шины при переломе костей голени?","a":["Наружную и внутреннюю шины — от середины бедра к стопе.","Наружную и внутреннюю шины — от паховой области к стопе.","Наружную — от середины бедра к стопе, внутреннюю — от паховой области к стопе.","Наружную — от паховой области к стопе, внутреннюю — от середины бедра к стопе."],"c":0,"e":"<p>При переломе костей голени накладываются 2 шины следующим образом: наружную и внутреннюю шины — от середины бедра к стопе.</p>","image":null},{"id":701011102,"themeId":16,"group":7010111,"chapter":65,"chapters":[65],"q":"Как необходимо накладывать шины при переломе нижней трети бедра?","a":["Наружную и внутреннюю шины — от паховой области к стопе.","Наружную и внутреннюю шины — от паховой области до коленного сустава.","Наружную — от подмышечной области к стопе, внутреннюю — от паховой области к стопе."],"c":2,"e":"<p>При переломе нижней трети бедра накладываются 2 шины следующим образом: наружная — от подмышечной области к стопе, внутренняя — от паховой области к стопе.</p>","image":null},{"id":701011201,"themeId":16,"group":7010112,"chapter":65,"chapters":[65],"q":"Как правильно оказать первую помощь при переломе костей таза?","a":["Наложить тугую повязку на место повреждения, пострадавшему придать полусидячее положение.","Пострадавшего уложить на спину, на твёрдую поверхность, к местам повреждения приложить горячую грелку.","Пострадавшего уложить на ровную, жёсткую поверхность, а под согнутые и разведённые коленные суставы подложить валик."],"c":2,"e":"<p>При переломе костей таза необходимо уложить пострадавшего на ровную, жёсткую поверхность, а под согнутые и разведённые коленные суставы подложить валик (поза лягушки).</p>","image":null},{"id":701011301,"themeId":16,"group":7010113,"chapter":65,"chapters":[65],"q":"Как необходимо оказать первую помощь при переломе ключицы у пострадавшего?","a":["Выпрямить руку, прибинтовать её к туловищу.","Прибинтовать согнутую в локте руку к туловищу.","Подложить валик из ваты или бинта в подмышечную область и прибинтовать согнутую в локте руку к туловищу."],"c":2,"e":"<p>Оказание первой помощи при переломе ключицы:</p> <ul><li>наложить косыночную или бинтовую повязку с ватно-марлевым валиком, помещённым в подмышечную область;</li> <li>прибинтовать согнутую в локте руку к туловищу.</li></ul> <p>Для фиксации плечевого пояса также используют крестообразную повязку, косыночную повязку, повязку Дезо, повязку Вельпо.</p>","image":null},{"id":701011302,"themeId":16,"group":7010113,"chapter":65,"chapters":[65],"q":"В каком из перечисленных ответов правильно указан способ оказания первой помощи при переломе ключицы у пострадавшего?","a":["Наложить холодный компресс на место перелома и туго забинтовать.","Наложить шину от подмышечной области на всю конечность и прибинтовать выпрямленную руку к туловищу.","Подложить валик из ваты или бинта в подмышечную область и прибинтовать согнутую в локте руку к туловищу."],"c":2,"e":"<p>Оказание первой помощи при переломе ключицы:</p> <ul><li>наложить косыночную или бинтовую повязку с ватно-марлевым валиком, помещённым в подмышечную область;</li> <li>прибинтовать согнутую в локте руку к туловищу.</li></ul> <p>Для фиксации плечевого пояса также используют крестообразную повязку, косыночную повязку, повязку Дезо, повязку Вельпо.</p>","image":null},{"id":701012101,"themeId":16,"group":7010121,"chapter":68,"chapters":[68],"q":"Какая повязка должна применяться при повреждении голеностопного сустава?","a":["Ползучая.","Спиральная.","Пращевидная.","Колосовидная.","Восьмиобразная."],"c":4,"e":"<p>При повреждении голеностопного сустава применяют восьмиобразные повязки. Повязка начинается с кругового хода над лодыжками, затем бинт спускают по тылу стопы на подошву и ведут вокруг стопы, поднимая по тылу и перекрещивая второй ход.</p> <p>Обойдя вокруг лодыжек, повторяют предыдущие ходы, делая перекрёсты выше и ниже предыдущих.</p>","image":null},{"id":701012201,"themeId":16,"group":7010122,"chapter":65,"chapters":[65],"q":"Как правильно снять с пострадавшего рубашку (пиджак) при ранении руки?","a":["Одежду снимать с обеих рук одновременно.","Одежду начинать снимать с повреждённой руки, затем освобождать здоровую руку.","Одежду начинать снимать со здоровой руки, затем освобождать повреждённую руку."],"c":2,"e":"<p>Рубашку (пиджак) при ранении руки с пострадавшего необходимо начинать снимать со здоровой руки, затем освобождать повреждённую руку.</p> <p>Это связано с тем, что больную руку нежелательно двигать, а при снятии рубашки или пиджака руку, с которой начинают снятие, приходится выворачивать.</p>","image":null},{"id":701012202,"themeId":16,"group":7010122,"chapter":68,"chapters":[68],"q":"Какой повязкой можно зафиксировать согнутой к туловищу повреждённую верхнюю конечность?","a":["Спиральной.","Косыночной.","Пращевидной.","Восьмиобразной.","Крестообразной."],"c":1,"e":"<p>Косыночная повязка создаётся из хлопчатобумажной ткани, которой придаётся вид равнобедренного треугольника различных размеров, но не меньше чем 80 × 80 × 113 сантиметров.</p> <p>Выпускаются косынки стандартных размеров: 100 × 100 × 136 сантиметров.</p> <p>Используется косынка в момент оказания первой доврачебной и медицинской помощи, а зачастую даже в момент критических ситуаций, а также тогда, когда потерпевшему необходимо создать временную иммобилизацию.</p> <p>Зачастую её используют для того, чтобы подвязать руку в том случае, когда повреждено плечо, предплечье, при переломах ключицы.</p> <p>Руку необходимо согнуть под прямым углом и подвести под неё косынку таким образом, чтобы верхний и длинный её конец уложился над ключицей с той стороны, где больная рука, а второй её конец должен находиться внизу, верх косынки должен выйти наружу из-под локтя. От предплечья больной руки необходимо завернуть нижний конец к верху, провести его на надплечьем назад к шее, где связать со второй частью косынки. Верхушку косынки необходимо загнуть вокруг локтя и укрепить спереди локтя при помощи булавки к повязке.</p>","image":null},{"id":701012301,"themeId":16,"group":7010123,"chapter":65,"chapters":[65],"q":"Откуда правильно начинать бинтовать грудную клетку при обширном её ранении?","a":["От подмышечных впадин.","С середины грудной клетки.","От нижних отделов грудной клетки."],"c":2,"e":"<p>Бинтовать грудную клетку при её ранении необходимо начинать от нижних отделов грудной клетки.</p> <p>Для этого бинт длиной около 1 м кладут на левое плечо, чтобы один конец висел на спине, другой — на груди. Спиральными круговыми ходами, накладывающимися друг на друга, бинтуют грудную клетку снизу вверх до подмышечных впадин и здесь завязывают или фиксируют английской булавкой.</p>","image":null},{"id":701012302,"themeId":16,"group":7010123,"chapter":68,"chapters":[68],"q":"В каком из перечисленных случаев необходимо накладывать герметизирующую повязку?","a":["При черепно-мозговой травме.","При артериальном кровотечении.","При проникающем ранении живота.","При повреждении голеностопного сустава.","При проникающем ранении грудной клетки."],"c":4,"e":"<p>Герметизирующую повязку накладывают при проникающем ранении грудной клетки для того, чтобы предотвратить дальнейшее попадание воздуха в плевральную полость.</p>","image":null},{"id":701012401,"themeId":16,"group":7010124,"chapter":68,"chapters":[68],"q":"В каком из перечисленных случаев накладывается пращевидная повязка?","a":["При переломе ключицы.","При переломе костей таза.","При челюстно-лицевой травме.","При переломе верхней конечности.","При проникающем ранении грудной клетки."],"c":2,"e":"<p>Пращевидная повязка — это полоска ткани, которая рассечена с обоих концов в продольном направлении.<br> В центре находится не рассеченный материал.</p> <p>Пращевидную повязку очень удобно накладывать при челюстно-лицевой травме.</p> <p>Последовательность действий:</p> <ul><li>разрезать бинт с обеих сторон вдоль — в центре остаётся неразрезанная часть длинной в 15–20 сантиметров (готовится «праща»);</li> <li>взять стерильный пинцет и, придерживая им стерильную салфетку, накрыть рану;</li> <li>в поперечном направлении положить пращу на салфетку, попарным образом связать концы пращи: нижние должны находиться наверху противоположной стороны головы, верхние должны быть в нижней части.</li></ul>","image":null},{"id":701013101,"themeId":16,"group":7010131,"chapter":70,"chapters":[70],"q":"Как необходимо оказать помощь пострадавшему при обморожении конечности?","a":["Обмороженную конечность растереть снегом, пострадавшего напоить горячим чаем.","Перенести пострадавшего в тёплое помещение (обогреваемый салон автомобиля), снять верхнюю и влажную одежду, укутать одеялом, дать горячее питьё, на поражённый участок наложить термоизолирующую повязку и (или) стерильную сухую повязку.","Обмороженную конечность опустить в горячую воду до покраснения, пострадавшему дать 100–150 граммов крепкого спиртного напитка."],"c":1,"e":"<p>Первая помощь состоит в прекращении охлаждения, согревании конечности, восстановления кровообращения в поражённых холодом тканях и предупреждения развития инфекции.</p> <p>Первое, что надо сделать при признаках обморожения — доставить пострадавшего в ближайшее тёплое помещение, снять промёрзшую обувь, носки, перчатки. Одновременно с проведением мероприятий первой помощи необходимо срочно вызвать врача, скорую помощь для оказания врачебной помощи.</p> <p>При обморожении I степени охлаждённые участки следует согреть до покраснения тёплыми руками, лёгким массажем, растираниями шерстяной тканью, дыханием, а затем наложить ватно-марлевую повязку.</p> <p>При обморожении II–IV степени быстрое согревание, массаж или растирание делать не следует. Наложите на поражённую поверхность теплоизолирующую повязку (слой марли, толстый слой ваты, вновь слой марли, а сверху клеёнку или прорезиненную ткань). Поражённые конечности фиксируют с помощью подручных средств (дощечка, кусок фанеры, плотный картон), накладывая и прибинтовывая их поверх повязки. В качестве теплоизолирующего материала можно использовать ватники, фуфайки, шерстяную ткань и пр.</p>","image":null},{"id":701014101,"themeId":16,"group":7010141,"chapter":66,"chapters":[66],"q":"Какой из бензинов наиболее ядовит?","a":["Этилированный.","Неэтилированный.","Бензины ядовиты в одинаковой степени."],"c":0,"e":"<p>Этилированный бензин содержит свинец, который обладает высокой канцерогенной активностью.</p>","image":null},{"id":701014102,"themeId":16,"group":7010141,"chapter":66,"chapters":[66],"q":"Опасен ли бензин, попавший на незащищённый участок кожи?","a":["Нет, не опасен. Бензином можно мыть руки.","Опасен. Бензин всасывается через поры кожи в кровь, вызывая отравление."],"c":1,"e":"<p>Бензин может оказывать вредное местное действие при попадании на кожу. Он способен проникать в организм человека даже через неповреждённую кожу, но так как в организме нет условий для его накапливания, то он быстро выделяется через лёгкие.</p> <p>Об этом свойстве бензина следует всегда помнить, так как вместе с бензином через кожу могут проникнуть различные вещества, растворённые в нём, например тетраэтилсвинец, имеющий тенденцию к накапливанию в организме и способный даже в незначительных количествах вызвать тяжёлые отравления.</p>","image":null},{"id":701014201,"themeId":16,"group":7010142,"chapter":66,"chapters":[66],"q":"Каковы первые симптомы (признаки) отравления бензином?","a":["Головокружение, тошнота, рвота.","Возбуждение, подобное опьянению, судороги скелетной мускулатуры.","Общая слабость, повышенное слюноотделение, замедление пульса, понижение температуры тела."],"c":2,"e":"<p>При непродолжительном вдыхании паров бензина (концентрация — 5000–10000 мг/м3) уже через несколько минут появляются головная боль, неприятные ощущения в горле, кашель, раздражение слизистой оболочки глаз, носа, покраснение кожи лица.</p> <p>Более продолжительное пребывание в такой атмосфере вызывает головокружение, неустойчивость походки, психическое возбуждение. Иногда развивается делирий, быстро сменяющийся состоянием апатии, вялости и депрессии.</p> <p>Первыми признаками острого отравления парами бензина являются также понижение температуры тела и артериального давления, замедление пульса.</p>","image":null},{"id":701014202,"themeId":16,"group":7010142,"chapter":66,"chapters":[66],"q":"Какие опасные последствия могут возникнуть при засасывании бензина ртом через трубку или шланг с целью перелива?","a":["Острое отравление бензином и его парами.","Разлив бензина и его воспламенение."],"c":0,"e":"<p>При засасывании бензина ртом через трубку или шланг с целью перелива происходит вдыхание паров бензина, а также возможны его заглатывание и случайная аспирация.</p> <p>При непродолжительном вдыхании паров бензина (концентрация — 5000–10000 мг/м3) уже через несколько минут появляются головная боль, неприятные ощущения в горле, кашель, раздражение слизистой оболочки глаз, носа, покраснение кожи лица. Более продолжительное пребывание в такой атмосфере вызывает головокружение, неустойчивость походки, психическое возбуждение. Иногда развивается делирий, быстро сменяющийся состоянием апатии, вялости и депрессии.</p> <p>Первыми признаками острого отравления парами бензина являются также понижение температуры тела и артериального давления, замедление пульса.</p> <p>При заглатывании бензина может появиться резкий мучительный кашель до рвоты продолжительностью 20–30 мин. Иногда после заглатывания бензина сразу же появляются боли в животе и рвота. Рвотные массы имеют типичный запах.</p> <p>В дальнейшем после бессимптомного периода (от 2 до 8 ч.) развивается «бензиновая пневмония». Появляются боли в правой половине грудной клетки, не позволяющие сделать глубокий вдох, затруднение дыхания, кашель. Всё это сопровождается головной болью, слабостью, ознобом, повышением температуры тела до 39°С. При объективном осмотре обращают на себя внимание бледность кожных покровов, цианоз губ. Дыхание поверхностное, до 40 в 1 мин. Правая половина грудной клетки отстаёт при дыхании. Пульс 100–120 ударов в минуту.</p>","image":null},{"id":701014501,"themeId":16,"group":7010145,"chapter":66,"chapters":[66],"q":"Каковы симптомы (признаки) отравления угарным газом?","a":["Мышечная слабость, сонливость, головокружение, тошнота, рвота.","Учащение пульса, сильная головная боль, повышение температуры.","Психическое возбуждение, расширение зрачков, появление галлюцинаций."],"c":0,"e":"<p>Клинически выделяют 3 степени отравления:</p> <ol><li>Лёгкая степень отравления угарным газом. Появляется головная боль в височной и лобной областях, часто опоясывающего характера (симптом «обруча»), головокружение, тошнота. Отмечается рвота, незначительное нарушение зрения. Больные жалуются на затруднённое дыхание, першение в горле, сухой кашель, неприятные ощущения в области сердца. Потеря сознания не наблюдается. Содержание карбоксигемоглобина в крови составляет 15–30%.</li> <li>Средняя степень отравления угарным газом. Отмечается тошнота, затруднённое дыхание, чувство нехватки воздуха, одышка. Нарушение психической активности проявляется возбуждением или оглушением, вплоть до комы. Появляются патологические рефлексы, миоз, анизокория. Обращает на себя внимание появление гиперемии кожи лица. Обязательно наличие хотя бы кратковременной потери сознания от 1–2 до 20 мин. Содержание карбоксигемоглобина в крови — 30–40%.</li> <li>Тяжёлая степень. Коматозное состояние различной глубины и продолжительности от нескольких часов до суток и более. Наблюдаются судороги, патологические рефлексы, парезы, параличи. Обращают на себя внимание кожные покровы пострадавшего: на месте происшествия они могут быть алого цвета, при поступлении в стационар в состоянии выраженной гипоксии их окраска меняется на цианотичный. За счёт развития острого риноларингита и трахеобронхита развивается нарушение дыхания, вплоть до остановки. Со стороны ССС — признаки острой левожелудочковой недостаточности. В крови метаболический ацидоз. Содержание карбоксигемоглобина в крови — 50–60%.</li></ol> <p>Для отравлений угарным газом средней и тяжёлой степени характерным осложнением является быстрое развитие буллезных дерматитов и ишемических полиневритов, появляющиеся через 10–15 часов после отравления.</p>","image":null},{"id":701014502,"themeId":16,"group":7010145,"chapter":66,"chapters":[66],"q":"Каков порядок оказания первой помощи пострадавшему при отравлении угарным газом?","a":["Пострадавшего уложить, согреть, напоить горячим напитком.","Вынести пострадавшего на чистый воздух, растереть тело, дать понюхать нашатырный спирт.","Перенести пострадавшего в прохладное место, уложить, охлаждать голову и область сердца с помощью холодных компрессов."],"c":1,"e":"<p>Самое первое и самое важное, что необходимо сделать при подозрении на отравление газом, — это в максимально возможном объёме обеспечить доступ свежего воздуха. Пострадавшего желательно вынести на улицу, если такой возможности нет, то нужно открыть все окна и двери в помещении и расстегнуть стесняющую одежду, растереть тело.</p> <p>Одновременно нужно вызвать скорую помощь. Если больной в сознании, нужно ему дать выпить слабощелочную воду или крепкий сладкий чай.</p> <p>По возможности следует остановить утечку и дальнейшее распространение угарного газа самостоятельно или вызвать аварийную службу.</p> <p>До приезда медицинской бригады, если пострадавший находится без сознания, ему следует поднести к носу кусочек ватки, обильно смоченный нашатырным спиртом.</p> <p>При отсутствии дыхания и сердцебиение нужно начинать реанимационные мероприятия — искусственную вентиляцию лёгких и непрямой массаж сердца.</p>","image":null},{"id":701015201,"themeId":16,"group":7010152,"chapter":71,"chapters":[71],"q":"Что необходимо сделать водителю, если в пути следования он заболел и его состояние ставит под угрозу безопасность дорожного движения?","a":["Прекратить намеченную поездку и вернуться домой для последующего лечения.","Прекратить дальнейшее движение и обратиться в ближайшее медицинское учреждение.","Снизить скорость движения, включить аварийную световую сигнализацию и следовать к месту стоянки с соблюдением мер предосторожности."],"c":1,"e":"<p>В случае заболевания водителя в пути, если он ставит под угрозу безопасность дорожного движения, он должен прекратить дальнейшее движение и обратиться в ближайшее медицинское учреждение.</p>","image":null},{"id":701015301,"themeId":16,"group":7010153,"chapter":71,"chapters":[71],"q":"Разрешается ли водителю управлять транспортным средством в состоянии алкогольного или наркотического опьянения?","a":["Запрещается.","Разрешается только при движении по прилегающей территории.","Разрешается только по дорогам с грунтовым покрытием при движении на незначительное расстоянии, при условии, что водитель не будет пересекать дороги с усовершенствованным покрытием."],"c":0,"e":"<p>Правила запрещают водителю управлять транспортным средством в состоянии алкогольного и (или) наркотического опьянения.</p>","image":null},{"id":701015302,"themeId":16,"group":7010153,"chapter":71,"chapters":[71],"q":"Каковы последствия приёма водителем алкоголя, наркотических средств?","a":["Сужение поля зрения.","Замедление реакции и снижение устойчивости внимания.","Потеря осторожности, переоценка собственных возможностей в сторону их завышения.","Всё вышеперечисленное."],"c":3,"e":"<p>Опасные последствия приёма водителем алкоголя, наркотиков и других возбуждающих средств: сужение поля зрения, замедление реакции и снижение устойчивости внимания, потеря осторожности, переоценка собственных возможностей в сторону их завышения.</p>","image":null},{"id":701016101,"themeId":16,"group":7010161,"chapter":69,"chapters":[69],"q":"Какое положение должно быть у пострадавшего с переломом ключицы при его транспортировке?","a":["Сидя.","Лёжа на боку.","Лёжа на спине.","Лёжа на животе."],"c":0,"e":"<p>Больного с переломом ключицы можно транспортировать в положении сидя или даже пешком.</p>","image":null},{"id":701016102,"themeId":16,"group":7010161,"chapter":69,"chapters":[69],"q":"В каких случаях из перечисленных пострадавшие должны транспортироваться в положении сидя?","a":["При переломе костей таза.","При черепно-мозговой травме.","При переломе ключицы, переломе рёбер.","При наличии повреждений верхних конечностей и органов брюшной полости."],"c":2,"e":"<p>Сидячее или полусидячее положение применяется в таких ситуациях:</p> <ul><li>травмы шеи;</li> <li>травмы грудной клетки;</li> <li>переломы ключицы, переломы рёбер, переломы рук.</li></ul>","image":null},{"id":701016103,"themeId":16,"group":7010161,"chapter":69,"chapters":[69],"q":"Какое положение должно быть у пострадавшего с проникающим ранением грудной клетки при его транспортировке?","a":["Стоя.","Лёжа на спине.","Лёжа на животе.","Лёжа на здоровом боку.","Лёжа на раненом боку или полусидя."],"c":4,"e":"<p>Транспортировать раненого в грудную клетку нужно в полусидячем положении или лёжа на раненом боку.</p>","image":null},{"id":701016201,"themeId":16,"group":7010162,"chapter":69,"chapters":[69],"q":"В каком положении правильно транспортировать пострадавшего с повреждением позвоночника?","a":["Стоя.","Сидя.","Лёжа на боку на жёстком щите.","Лёжа на спине на жёстком щите."],"c":3,"e":"<p>Транспортировка больного с травмой позвоночника и спинного мозга должна осуществляться только при наличии иммобилизации. Для иммобилизации при переломах грудного и поясничного отделов позвоночника для транспортировки с места травмы в стационар пользуются жёсткими носилками и различного рода щитами, на которые больного укладывают на спину или на живот.</p> <p>Во избежание смещения отломков позвонков и дополнительного повреждения спинного мозга не следует транспортировать больного в положении на боку.</p> <p>Очень важным моментом при оказании помощи больному с травмой позвоночника и спинного мозга является бережная укладка его на носилки. Поднимать больного и перекладывать на носилки необходимо сразу, в один приём, при помощи 3–5 человек, обязательно поддерживая голову (особенно при травме в шейном отделе). Нежелательно повторное, тем более многократное перекладывание пострадавшего.</p>","image":null},{"id":701016202,"themeId":16,"group":7010162,"chapter":69,"chapters":[69],"q":"В каком случае необходимо транспортировать пострадавшего лежа на спине с согнутыми и разведёнными в коленных суставах ногами?","a":["При травме живота.","При переломе ключицы.","При черепно-мозговой травме.","При травме груди и верхних конечностей.","При повреждении органов брюшной полости или переломе костей таза."],"c":4,"e":"<p>При повреждении органов брюшной полости или переломе костей таза необходимо транспортировать пострадавшего лежа на спине с согнутыми и разведенными в коленных суставах ногами. Такая поза позволяет уберечь сосуды и окружающие ткани от травмирования обломками костей.</p>","image":null},{"id":701016301,"themeId":16,"group":7010163,"chapter":69,"chapters":[69],"q":"В каком положении транспортируют пострадавшего с переломом челюсти, находящегося в удовлетворительном состоянии?","a":["Сидя.","Лёжа на боку.","Лёжа на спине."],"c":0,"e":"<p>При удовлетворительном состоянии пациента транспортируют в полусидячем положении.</p> <p>При отсутствии сознания пациента укладывают на носилки вниз лицом, положив под грудь и голову скатанное одеяло или одежду. Во время транспортировки наблюдают за дыханием пациента.</p>","image":null},{"id":701016302,"themeId":16,"group":7010163,"chapter":69,"chapters":[69],"q":"В каком положении при транспортировке должен находиться пострадавший в бессознательном состоянии при переломе челюсти во избежание механического удушья?","a":["Сидя.","Лёжа на боку или лёжа лицом вниз.","Лёжа на спине."],"c":1,"e":"<p>Пострадавший имеет травму (перелом челюсти) и нарушение сознания. При потере сознания независимо от причины нужно опасаться асфиксии (нарушения доступа кислорода в лёгкие) вследствие западения языка или регургитации желудочного содержимого (с попаданием его в лёгкие). Поэтому пострадавшего перевозят или на боку, или (предпочтительнее) на животе (в этом положении снижается риск механического осложнения травмы).</p> <p>При транспортировке на животе пациента укладывают на специально оборудованные носилки (с прорезью для лица) либо на носилки вниз лицом, положив под грудь и голову скатанное одеяло или одежду. Во время транспортировки наблюдают за дыханием пациента.</p> <p>При переломе челюсти нам необходимо создать иммобилизацию (неподвижность) места перелома. При переломе челюсти в полевых условиях накладывается пращевидная повязка.</p>","image":null},{"id":701016303,"themeId":16,"group":7010163,"chapter":69,"chapters":[69],"q":"В каком положении при транспортировке должен находиться пострадавший в случае потери им сознания вследствие черепно-мозговой травмы?","a":["Стоя.","Сидя.","Лёжа на боку или лёжа лицом вниз.","Лёжа на спине."],"c":2,"e":"<p>Транспортировка пострадавшего с черепно-мозговой травмой во всех случаях — от лёгкого до тяжёлого — производится в положении лёжа на боку или лёжа лицом вниз, без полной иммобилизации тела.</p>","image":null},{"id":701017101,"themeId":16,"group":7010171,"chapter":71,"chapters":[71],"q":"Какие из перечисленных транспортных средств должны быть укомплектованы медицинской аптечкой?","a":["Мопед.","Велосипед.","Мотоцикл с боковым прицепом.","Мотоцикл без бокового прицепа.","Все перечисленные транспортные средства разрешено не укомплектовывать медицинской аптечкой."],"c":2,"e":"<p>Медицинской аптечкой должны быть оснащены следующие транспортные средства: автобусы, грузовые и легковые автомобили, колёсные тракторы и мотоциклы с колясками.</p>","image":null},{"id":701017102,"themeId":16,"group":7010171,"chapter":71,"chapters":[71],"q":"В каком из перечисленных мест в автомобиле разрешено хранить аптечку?","a":["В багажнике.","В салоне автомобиля.","Только в месте, установленном изготовителем данного транспортного средства.","В любом из перечисленных мест."],"c":2,"e":"<p>Автомобильную медицинскую аптечку необходимо хранить в закреплённом состоянии в местах, установленных изготовителем данного транспортного средства.</p>","image":null},{"id":701017201,"themeId":16,"group":7010172,"chapter":71,"chapters":[71],"q":"Для чего применяется 10-процентный раствор аммиака (нашатырный спирт), входящий в комплект медицинской аптечки для транспортных средств?","a":["Для смазывания обожжённых мест.","Для вдыхания при обмороке, угаре.","Как средство, успокаивающее боли в области сердца.","Для обработки края раны при повреждении кожи и тканей."],"c":1,"e":"<p>Входящий в комплект медицинской аптечки, которой оснащены автотранспортные средства, 10 процентный раствор аммиака (нашатырный спирт) применяется для вдыхания при обмороке, угаре.</p>","image":null},{"id":701017271,"themeId":16,"group":7010172,"chapter":71,"chapters":[71],"q":"Для чего предназначено входящее в состав медицинской аптечки изотермическое одеяло?","a":["Для защиты пострадавшего от ветра и осадков.","Для защиты пострадавшего от прямых солнечных лучей.","Для предупреждения перегрева пострадавшего.","Для предупреждения переохлаждения пострадавшего.","Для всего вышеперечисленного."],"c":4,"e":"<p>Одеяло изотермическое используется для <strong>предупреждения переохлаждения или перегрева</strong> пострадавшего, <strong>защиты от прямых солнечных лучей, ветра и осадков</strong>.</p>","image":"assets/adrive-questions/q701017271.jpg"},{"id":701017272,"themeId":16,"group":7010172,"chapter":71,"chapters":[71],"q":"Как правильной использовать изотермическое одеяло, если необходимо предохранить пострадавшего от переохлаждения?","a":["Одеяло должно быть обращено к человеку серебристой поверхностью.","Одеяло должно быть обращено к человеку золотистой поверхностью."],"c":0,"e":"<p>Серебристая поверхность обладает теплоудерживающими свойствами, поэтому <strong>при холодной погоде она должна быть обращена к человеку</strong>. В жару или при пожаре наоборот: укрываться спасательным покрывалом нужно изолирующей золотой стороной к телу.</p>","image":"assets/adrive-questions/q701017272.jpg"},{"id":701017273,"themeId":16,"group":7010172,"chapter":71,"chapters":[71],"q":"Для чего применяется входящий в состав медицинской аптечки гипотермический охлаждающий пакет?","a":["Для снижения болевой реакции и уменьшения отёка.","Для охлаждения области сердца при жалобе пострадавшего на сердечную боль.","Для предохранения пострадавшего от перегрева."],"c":0,"e":"<p>Пакет гипотермический охлаждающий применяют <strong>для снижения болевой реакции</strong> при различных видах повреждений, <strong>уменьшения отёка</strong>.</p>","image":"assets/adrive-questions/q701017273.jpg"},{"id":701017274,"themeId":16,"group":7010172,"chapter":71,"chapters":[71],"q":"Как правильно воспользоваться гипотермическим охлаждающим пакетом?","a":["Не нарушая целостности пакета, приложить его к ушибу. Пакет зафиксировать нестерильным бинтом или пластырем.","Положить пакет на гладкую поверхность, раздавить внутренний пакетик с жидкостью, интенсивно встряхнуть несколько раз, положить на место ушиба.","Содержимое пакета вскрыть, вылить на стерильную повязку, наложенную на место ушиба."],"c":1,"e":"<p>Положить пакет на гладкую поверхность, основой ладони <strong>раздавить внутренний пакетик с водой</strong>, интенсивно <strong>встряхнуть 10–15 раз</strong>, положить на место травмы при ушибах, гематомах, при локальных ожогах положить к стерильной повязке.</p>","image":"assets/adrive-questions/q701017274.jpg"},{"id":701017275,"themeId":16,"group":7010172,"chapter":71,"chapters":[71],"q":"Как правильно использовать медицинскую салфетку для стимуляции дыхания?","a":["Салфетку подносят к носу пострадавшего и дают сделать 1-2 вдоха, при необходимости процедуру повторяют.","Салфетку подносят к носу пострадавшего и оставляют на 1-2 минуты для облегчения дыхания."],"c":0,"e":"<p>Салфетка медицинская для стимуляции дыхания (с пропиткой) используется для стимуляции дыхания пострадавших, выведения из обморочного состояния. Вскрывают упаковку с салфеткой, подносят к носу пострадавшего и <strong>дают сделать 1-2 вдоха</strong>, при необходимости процедуру повторяют.</p>","image":"assets/adrive-questions/q701017275.jpg"},{"id":701017276,"themeId":16,"group":7010172,"chapter":71,"chapters":[71],"q":"Как правильно применяются стерильные салфетки или бактерицидный пластырь из состава автомобильной медицинской аптечки?","a":["Салфетки или лейкопластырь накладываются только после тщательного промывания раны и удаления с её поверхности инородных предметов.","Наложение лейкопластыря бактерицидного не требует дополнительной обработки раны, перед наложением стерильной салфетки незначительную рану можно обработать перекисью водорода, при глубоких и загрязнённых ранах, обработать перекисью водорода края раны.","Перед наложением пластыря или стерильной салфетки необходимо обработать рану 10%-ным раствором аммония или салфетками с содержанием аммиака."],"c":1,"e":"<p>Применение бактерицидного пластыря на небольшие раны и ссадины не требует дополнительной обработки раневой поверхности. <strong>Запрещается удалять инородные предметы из глубоких и загрязнённых ран</strong>. Допускается обработка незначительных ран перекисью водорода, при глубоких ранах следует обрабатывать только края раны.</p>","image":"assets/adrive-questions/q701017276.jpg"},{"id":701018101,"themeId":16,"group":7010181,"chapter":71,"chapters":[71],"q":"Какова последовательность действий водителя – очевидца ДТП, при котором произошло возгорание автомобиля с пострадавшим?","a":["Потушить при помощи огнетушителя автомобиль, извлечь пострадавшего из автомобиля, остановить кровотечение, определить наличие иных повреждений, их характер и оказать соответствующую первую помощь.","Извлечь пострадавшего из автомобиля, снять с него горящую одежду, остановить кровотечение, определить наличие повреждений, характер травмы и оказать соответствующую первую помощь.","Извлечь пострадавшего из автомобиля, потушить горящую одежду, остановить кровотечение, определить наличие повреждений, характер травмы и оказать соответствующую первую помощь."],"c":2,"e":"<p>Последовательность действий при оказании первой помощи при ДТП:</p> <ul><li>извлечь пострадавшего из автомобиля;</li> <li>потушить горящую одежду;</li> <li>остановить наружное кровотечение;</li> <li>определить наличие повреждений, характер травмы и оказать соответствующую первую помощь.</li></ul>","image":null},{"id":701018201,"themeId":16,"group":7010182,"chapter":71,"chapters":[71],"q":"Что обязан в первую очередь сделать водитель, оказавший первую помощь пострадавшему при ДТП?","a":["Сообщить о случившемся в милицию.","Записать фамилии, адреса очевидцев ДТП.","Вызвать скорую помощь, а если это невозможно — доставить пострадавшего в ближайшее медицинское учреждение."],"c":2,"e":"<p>Водитель, оказавший попавшему в ДТП пострадавшему первую помощь, обязан вызвать скорую помощь или доставить пострадавшего в ближайшее лечебное учреждение.</p>","image":null}];